import{_ as e,o as i,c as t,a2 as a}from"./chunks/framework.CE5oItKu.js";const p=JSON.parse('{"title":"Mango PMO 总流程","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/00-dev-flow.md","filePath":"mango-pmo/rules/00-dev-flow.md"}'),o={name:"mango-pmo/rules/00-dev-flow.md"};function d(r,l,n,c,h,u){return i(),t("div",null,[...l[0]||(l[0]=[a('<h1 id="mango-pmo-总流程" tabindex="-1">Mango PMO 总流程 <a class="header-anchor" href="#mango-pmo-总流程" aria-label="Permalink to &quot;Mango PMO 总流程&quot;">​</a></h1><h2 id="_1-定位" tabindex="-1">1. 定位 <a class="header-anchor" href="#_1-定位" aria-label="Permalink to &quot;1. 定位&quot;">​</a></h2><ul><li><code>mango-pmo</code> 是 Mango 的唯一规范源。</li><li><code>mango-docs</code> 只放设计文档、Sprint 计划、交付记录。</li><li>规范、流程、角色、Skill 一律放 <code>mango-pmo</code>。</li></ul><h2 id="_2-目标" tabindex="-1">2. 目标 <a class="header-anchor" href="#_2-目标" aria-label="Permalink to &quot;2. 目标&quot;">​</a></h2><ul><li>AI 能基于 Mango 完成一句话需求。</li><li>产出可开发、可验证、可发布的结果。</li><li>降低歧义、返工、越权、遗漏。</li></ul><h2 id="_3-标准流程" tabindex="-1">3. 标准流程 <a class="header-anchor" href="#_3-标准流程" aria-label="Permalink to &quot;3. 标准流程&quot;">​</a></h2><h3 id="_3-0-业务消费-mango-问题处理" tabindex="-1">3.0 业务消费 Mango 问题处理 <a class="header-anchor" href="#_3-0-业务消费-mango-问题处理" aria-label="Permalink to &quot;3.0 业务消费 Mango 问题处理&quot;">​</a></h3><p>业务开发使用 Mango 时发现疑似 Mango 框架、starter、CLI、模板、前端包或发布物料问题，必须先按 <a href="./07-mango-issue-runbook">Mango Issue 登记 Runbook</a> 归因、登记和回写任务记录。</p><p>本节只保留流程入口；Issue 触发条件、登记字段、阻塞处理和任务结束提醒统一维护在 <code>rules/07-mango-issue-runbook.md</code>。</p><h3 id="_3-0-1-pmo-加载原则" tabindex="-1">3.0.1 PMO 加载原则 <a class="header-anchor" href="#_3-0-1-pmo-加载原则" aria-label="Permalink to &quot;3.0.1 PMO 加载原则&quot;">​</a></h3><ul><li>preflight 只加载本次任务必须遵守的最小规范集。</li><li><code>rules/00-dev-flow.md</code> 和 <code>rules/03-ai-coding-redlines.md</code> 是正式任务基线。</li><li><code>rules/01-delivery-contract.md</code> 只在正式需求、设计、开发、测试、验收、发布、PR 或交付台账任务中加载。</li><li>领域规范只在路径或任务关键词命中时加载；禁止因为“前端”“后端”泛词一次性加载整套规范。</li><li>简单问答、只读定位、状态查看、日志查看、目录查看、worktree 列表不触发正式流程。</li><li>规范、设计文档、交付记录等不影响服务代码的治理改动，可在 <code>main</code> 直接修改提交；仍需执行 PMO preflight。</li></ul><p>PMO preflight 的首要目的不是审批命令，而是在正式交付前刷新 Agent 对本项目规范的记忆。Agent 必须先识别用户意图和规范遗漏风险，再决定是否进入 PMO。</p><p>Agent 在长会话和复杂任务中容易出现以下问题：</p><ul><li>忘记本项目已有规范，按通用经验或旧习惯执行。</li><li>想不到本次任务对应的前端、后端、数据库、测试、发布、文档或工作区规则。</li><li>只关注眼前报错，忽略权限、租户、真实数据、验证证据和发布影响。</li><li>顺手扩大范围、修历史问题，或把非本次问题混入当前交付。</li><li>用“能编译、能启动、能打开页面”替代真实验收。</li></ul><p>判定原则：</p><ul><li>先判断用户意图：是交付变更、方案/验收、发布/提交，还是查看、同步、定位、本地运维。</li><li>再判断风险：是否存在规范遗漏风险，或会影响受版本控制文件、服务行为、接口/数据库/测试/构建、发布物料、长期规范或交付结论。</li><li>用户意图是“交付一个变更”，或风险会影响可交付结果时执行。</li><li>用户意图只是“查看状态、同步仓库、整理本地环境”，且风险只限本地状态时不执行。</li><li>如果不触发的操作过程中发现需要人工修改文件、解决冲突、修复问题或形成交付结论，先停止当前操作，再按实际任务执行 preflight。</li></ul><p>意图与风险判定：</p><table tabindex="0"><thead><tr><th>用户意图</th><th>风险特征</th><th>是否执行</th></tr></thead><tbody><tr><td>查看、解释、定位、列举</td><td>只读，不改变仓库和运行态</td><td>不执行</td></tr><tr><td>纯同步仓库</td><td>只执行 fast-forward/fetch，不解决冲突、不形成验证结论</td><td>不执行</td></tr><tr><td>本地运维</td><td>只影响本机进程、缓存、端口、未跟踪临时文件</td><td>不执行</td></tr><tr><td>编码、修复、重构、配置变更</td><td>需要召回开发、测试、边界、工作区规范</td><td>执行</td></tr><tr><td>设计、测试方案、验收、发布、提交、PR</td><td>需要召回交付、证据、发布、PR 规范</td><td>执行</td></tr><tr><td>规范、流程、Agent 入口治理</td><td>需要召回规范唯一源和文档归档规则</td><td>执行</td></tr><tr><td>冲突处理、失败修复、回滚选择</td><td>需要人工判断并改变代码或历史</td><td>执行</td></tr></tbody></table><p>以下情况必须执行：</p><ul><li>按设计文档、plan、Sprint 计划或交付台账进行开发、验证、发布或治理。</li><li>人工新增或修改代码、接口、数据库、测试、前端页面、构建配置。</li><li>新增或修改设计文档、Sprint 计划、交付记录、规范或 Agent 入口。</li><li>做架构设计、技术方案、测试方案、验收、发布、提交或 PR。</li><li>处理 <code>git pull</code>、<code>rebase</code>、<code>merge</code> 产生的冲突，或为同步后的失败检查做修复。</li><li>用户明确要求“按 PMO / 按计划 / 按设计文档 / 按交付台账”推进。</li></ul><p>以下情况不需要执行：</p><ul><li>简单问答、概念解释、使用说明。</li><li>只读定位文件、类、接口、配置或快速查看模块现状。</li><li>查看 git 状态、目录结构、日志、报错片段，但不进入修复或交付。</li><li>执行纯仓库同步命令，例如 <code>git fetch</code>、<code>git pull --ff-only</code>、<code>git remote update</code>，且不人工编辑文件、不解决冲突、不做交付验证。</li><li>查看或刷新 GitHub Issue、PR、分支、tag、release 列表，但不创建、修改或发布。</li><li>安装依赖、清理本地缓存、停止本地进程、查看端口占用等本地运维操作，且不修改受版本控制文件。</li><li>用户明确要求“先快速看看 / 暂不进入 PMO 流程”。</li></ul><h3 id="_3-0-2-工作区策略" tabindex="-1">3.0.2 工作区策略 <a class="header-anchor" href="#_3-0-2-工作区策略" aria-label="Permalink to &quot;3.0.2 工作区策略&quot;">​</a></h3><p>PMO preflight 必须输出本次任务的工作区策略：</p><ul><li><code>worktree-required</code>：必须使用任务专用 Git worktree 和任务分支。</li><li><code>main-direct-allowed</code>：可在主工作区直接修改并提交。</li><li><code>needs-human-check</code>：影响范围不足，必须先确认路径或任务边界。</li></ul><p>以下改动必须使用任务 worktree：</p><ul><li>代码、接口、数据库、测试、前端页面、构建配置。</li><li><code>mango/**</code>、<code>mango-ui/**</code>、<code>mango-business-starter/**</code>、<code>scripts/**</code>、<code>.github/**</code>。</li><li><code>package.json</code>、<code>pnpm-lock.yaml</code>、<code>pom.xml</code>、migration、<code>src/**</code>。</li><li>发布脚本、启动脚本、CLI、starter、模板和发布物料。</li></ul><p>以下改动可在主工作区直接提交：</p><ul><li><code>mango-pmo/**</code> 规范、流程、Agent 定义和 PMO 工具治理。</li><li><code>mango-docs/**</code> 设计文档、Sprint 计划、交付记录和历史材料。</li><li><code>AGENTS.md</code>、<code>CLAUDE.md</code>、<code>GEMINI.md</code> 入口路由。</li></ul><p>只要同一任务同时触及必须 worktree 的文件，整项任务必须使用 worktree。</p><p>同一任务或同一 PR 在本地只能对应一个开发 worktree。验收返工、Review 修改、CI 修复、PR 门禁修复和交付台账未完成项属于当前任务返工时，必须复用原任务 worktree 和原任务分支。</p><h3 id="_3-1-需求" tabindex="-1">3.1 需求 <a class="header-anchor" href="#_3-1-需求" aria-label="Permalink to &quot;3.1 需求&quot;">​</a></h3><p>必须完成：</p><ol><li>明确目标</li><li>明确范围</li><li>明确验收标准</li><li>为关键对象、关键流程、业务规则、页面和主要动作建立可追踪验收项</li><li>按 <a href="./01-delivery-contract">交付契约与设计说明规则</a> 明确交付契约</li></ol><p>产出：</p><ul><li>需求说明</li></ul><h3 id="_3-2-设计" tabindex="-1">3.2 设计 <a class="header-anchor" href="#_3-2-设计" aria-label="Permalink to &quot;3.2 设计&quot;">​</a></h3><p>必须完成：</p><ol><li>明确影响模块</li><li>明确接口变化</li><li>明确数据变化</li><li>明确测试范围</li><li>按 <a href="https://github.com/HardyDou/mango/blob/main/mango-pmo/rules/09-test-case-automation-flow.md" target="_blank" rel="noreferrer">测试用例与自动化工程化流程</a> 建立测试用例候选、自动化层级和执行策略</li><li>按 <a href="./01-delivery-contract">交付契约与设计说明规则</a> 建立交付台账</li></ol><p>产出：</p><ul><li>设计说明</li></ul><h3 id="_3-3-开发" tabindex="-1">3.3 开发 <a class="header-anchor" href="#_3-3-开发" aria-label="Permalink to &quot;3.3 开发&quot;">​</a></h3><p>必须完成：</p><ol><li>确认交付契约、设计说明和交付台账已建立</li><li>从 <code>main</code> 新建独立 Git worktree 和任务分支</li><li>在任务 worktree 内按规范编码</li><li>新增代码遵守最新规则</li><li>不扩大历史债务</li></ol><p>禁止：</p><ul><li>直接在主工作区或 <code>main</code> 分支上做代码、接口、数据库、测试、前端页面或构建配置改动。</li><li>多个任务共用同一个开发 worktree。</li></ul><p>例外：</p><ul><li>只修改规范、流程、设计文档、交付记录、Agent 入口或 PMO 临时复盘，且不影响服务代码、接口、数据库、测试、前端页面或构建配置时，可在 <code>main</code> 直接提交。</li></ul><p>产出：</p><ul><li>代码</li><li>必要测试</li></ul><h3 id="_3-4-验证" tabindex="-1">3.4 验证 <a class="header-anchor" href="#_3-4-验证" aria-label="Permalink to &quot;3.4 验证&quot;">​</a></h3><p>必须完成：</p><ol><li>运行对应检查命令</li><li>验证改动范围</li><li>记录未完成项和风险</li><li>按交付台账逐项验证</li><li>按测试用例优先级执行自动化或手工验收，并沉淀测试结果基线</li></ol><p>产出：</p><ul><li>验证结果</li></ul><h3 id="_3-4-1-任务中发现新问题" tabindex="-1">3.4.1 任务中发现新问题 <a class="header-anchor" href="#_3-4-1-任务中发现新问题" aria-label="Permalink to &quot;3.4.1 任务中发现新问题&quot;">​</a></h3><p>适用于 Mango 开发者、Mango 维护者和业务开发者在开发、联调、回归测试、验收或发布验证中发现的新问题。</p><p>必须先判断问题归属：</p><ol><li>如果问题由本次任务改动引入，必须纳入当前任务直接修复，并补充对应回归验证。</li><li>如果问题不是本次任务改动引入，必须登记 Issue，记录复现路径、影响范围、证据和建议优先级，然后回到当前任务主线。</li><li>如果无法判断是否由本次任务引入，必须对比主分支、发布物料或任务前基线；仍无法判断时，按风险记录 Issue，并在交付报告中说明未归因风险。</li></ol><p>禁止：</p><ul><li>把非本次任务引入的问题顺手扩展成当前任务范围。</li><li>因为发现历史问题而中断当前任务主线。</li><li>未登记 Issue 就把已确认的非本次问题留作口头记录。</li><li>用 Issue 逃避本次任务引入的缺陷修复。</li></ul><h3 id="_3-4-2-任务返工与验收缺陷修复" tabindex="-1">3.4.2 任务返工与验收缺陷修复 <a class="header-anchor" href="#_3-4-2-任务返工与验收缺陷修复" aria-label="Permalink to &quot;3.4.2 任务返工与验收缺陷修复&quot;">​</a></h3><p>验收、Review、CI 或 PR 检查中发现的问题，必须先判断是否属于当前任务或当前 PR。</p><p>必须执行：</p><ol><li>如果问题由当前任务或当前 PR 引入，属于同一任务返工，必须回到原任务 worktree 和原任务分支修复。</li><li>同一任务返工包括验收发现的 bug、Review 修改意见、CI 失败、PR 门禁失败和交付台账未完成项。</li><li>修复前必须先执行 <code>git worktree list</code>，确认是否已有当前任务分支或 PR 分支对应的 worktree。</li><li>原 worktree 不可用时，必须优先基于原任务分支重建 worktree，并在交付报告中说明原因。</li><li>如果问题不是当前任务引入，必须登记 Issue 或 PR 评论，并等待用户确认是否作为新任务处理。</li></ol><p>禁止：</p><ul><li>同一任务返工时新建无关联 worktree。</li><li>同一任务返工时新建无关联修复分支。</li><li>将当前任务引入的缺陷拆成新任务来规避原任务验收。</li></ul><h3 id="_3-5-提交" tabindex="-1">3.5 提交 <a class="header-anchor" href="#_3-5-提交" aria-label="Permalink to &quot;3.5 提交&quot;">​</a></h3><p>必须完成：</p><ol><li>在任务 worktree 内完成验证</li><li>提交前先将最新 <code>main</code> 合并到任务分支，并处理冲突</li><li>合并 <code>main</code> 后重新执行受影响验证</li><li>提交代码</li><li>Push 任务分支</li><li>使用 <code>gh</code> 创建 PR</li><li>说明改动范围</li><li>说明验证结果</li><li>说明遗留问题</li><li>说明交付台账总项、完成项和例外项</li></ol><p>PR 要求：</p><ul><li>禁止绕过 PR 直接把任务分支合并到 <code>main</code>。</li><li>PR 创建后必须保留任务 worktree，直到 PR 已合并。</li><li>PR 合并后，必须使用开发环境规范中的 worktree 删除脚本清理任务 worktree。</li></ul><p>产出：</p><ul><li>Commit</li><li>已创建 PR</li></ul><h2 id="_4-文档放置规则" tabindex="-1">4. 文档放置规则 <a class="header-anchor" href="#_4-文档放置规则" aria-label="Permalink to &quot;4. 文档放置规则&quot;">​</a></h2><h3 id="_4-1-mango-pmo" tabindex="-1">4.1 <code>mango-pmo</code> <a class="header-anchor" href="#_4-1-mango-pmo" aria-label="Permalink to &quot;4.1 `mango-pmo`&quot;">​</a></h3><p>只放：</p><ul><li>规范</li><li>流程</li><li>Agent 定义</li><li>Skill 约束</li></ul><h3 id="_4-2-mango-docs" tabindex="-1">4.2 <code>mango-docs</code> <a class="header-anchor" href="#_4-2-mango-docs" aria-label="Permalink to &quot;4.2 `mango-docs`&quot;">​</a></h3><p>只放：</p><ul><li>架构设计</li><li>Sprint 计划</li><li>交付记录</li><li>历史设计</li></ul><p>禁止：</p><ul><li>在 <code>mango-docs</code> 新增规范文件</li><li>在 <code>mango-docs</code> 维护规则入口</li><li>在 <code>mango-docs</code> 写“必须遵守”的长期规则</li></ul><h2 id="_5-角色分工" tabindex="-1">5. 角色分工 <a class="header-anchor" href="#_5-角色分工" aria-label="Permalink to &quot;5. 角色分工&quot;">​</a></h2><h3 id="_5-1-使用者定义" tabindex="-1">5.1 使用者定义 <a class="header-anchor" href="#_5-1-使用者定义" aria-label="Permalink to &quot;5.1 使用者定义&quot;">​</a></h3><table tabindex="0"><thead><tr><th>使用者</th><th>定义</th><th>主要边界</th></tr></thead><tbody><tr><td>Mango 维护者</td><td>维护 Mango 主仓、发布物料、PMO 规范、CLI、starter、框架能力和公共模块的人或 Agent</td><td>可以修改 Mango 框架、模板、规范和发布流程；必须保证发布物料彼此兼容</td></tr><tr><td>Mango 开发者</td><td>在 Mango 主仓内开发框架能力、平台模块、公共组件、CLI 和 starter 的人或 Agent</td><td>面向可复用能力开发；不得把单一业务项目逻辑写入 Mango 通用模块</td></tr><tr><td>业务开发者</td><td>在企业业务项目内基于 Mango 发布物料开发业务模块的人或 Agent</td><td>依赖 Mango CLI、starter、前后端包和业务 PMO 基线开发；不得直接修改 Mango 主仓来交付单一业务需求</td></tr></tbody></table><p>Mango 维护者和 Mango 开发者面向框架通用性负责；业务开发者面向企业业务交付负责。</p><h3 id="_5-2-agent-角色" tabindex="-1">5.2 Agent 角色 <a class="header-anchor" href="#_5-2-agent-角色" aria-label="Permalink to &quot;5.2 Agent 角色&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>负责</th></tr></thead><tbody><tr><td>PM Agent</td><td>需求说明、范围、验收标准</td></tr><tr><td>Tech Lead Agent</td><td>设计、模块边界、接口、任务拆分</td></tr><tr><td>Dev Agent</td><td>开发、测试、提交</td></tr><tr><td>QA Agent</td><td>测试范围、执行结果</td></tr><tr><td>PMO Agent</td><td>规范、流程、资产治理</td></tr></tbody></table><h2 id="_6-执行原则" tabindex="-1">6. 执行原则 <a class="header-anchor" href="#_6-执行原则" aria-label="Permalink to &quot;6. 执行原则&quot;">​</a></h2><ul><li>规则优先于习惯</li><li>新规则只写一次，只放 <code>mango-pmo</code></li><li>新代码遵守新规则</li><li>老代码按模块渐进重构</li><li>设计文档不作为规范源</li></ul><h2 id="_7-禁止事项" tabindex="-1">7. 禁止事项 <a class="header-anchor" href="#_7-禁止事项" aria-label="Permalink to &quot;7. 禁止事项&quot;">​</a></h2><ul><li>没有范围和验收标准就直接开发</li><li>没有交付契约和设计说明就直接开发</li><li>在设计文档里定义长期规则</li><li>同一规则在多个目录维护</li><li>明知已有规范仍写第二份</li></ul>',93)])])}const m=e(o,[["render",d]]);export{p as __pageData,m as default};
